    "weeds":{def:"Wild plants that grow where they are not wanted and take space from garden plants.",pos:"noun"},
    "watering can":{def:"A container with a long spout used to water plants.",pos:"noun"},
    "puzzle":{def:"Something that requires careful thought to understand or solve.",pos:"noun"},
    "sweeter":{def:"Tasting more sweet — more sugary and pleasant.",pos:"adjective"}
