STORIES[3][4].push({
  id:"l3.5s5", levelId:3, subLevel:4,
  title:"The Night the Power Went Out", emoji:"🕯️", genre:"Everyday Life",
  wordCount:324, readMins:3,
  blurb:"A power cut on a winter evening — and what comes out of the darkness.",
  paragraphs:[
    "The power went out at seven-fifteen on a Thursday in January. One moment the house was its usual self — television, ceiling lights, the hum of the refrigerator — and the next it was dark and quiet in a way that felt total. My sister said she had not heard silence like that since we went camping.",
    "My parents found the candles. We have a tin of them in the kitchen drawer for exactly this purpose. My father lit five and put them in different rooms. The house looked completely different. The familiar rooms had new shadows, new proportions. Things you never noticed — the texture of the wallpaper, the shape of the ceiling rose — became visible.",
    "My mother rang the electricity company and was told the fault was on the main line and would be repaired by ten. We had three hours. Without screens, nobody quite knew what to do for the first ten minutes. Then my grandmother, who was visiting, said she would teach us to play a card game called Spite and Malice, which she had played with her own grandmother as a child.",
    "She taught us the rules at the kitchen table by candlelight. It took a few rounds to understand, and there was an argument about whether my father was cheating, which he was not. By nine, we were good enough to play without asking about the rules every five minutes. My sister won three games out of five.",
    "The power came back at exactly ten, as promised. Every screen in the house lit up simultaneously, along with the refrigerator hum and the ceiling lights. The candlelit kitchen was over in a second. My sister said it was a pity. My grandmother said she could come back and teach us Canasta."
  ],
  vocabulary:{
    "total":{def:"Here: complete and absolute, with no exceptions.",pos:"adjective"},
    "ceiling rose":{def:"A decorative plaster circle on the ceiling where a light fitting is attached.",pos:"noun"},
    "fault":{def:"A break or failure in an electrical system.",pos:"noun"},
    "Spite and Malice":{def:"A competitive two-player card game, also known as Cat and Mouse.",pos:"noun"},
    "simultaneously":{def:"At exactly the same time.",pos:"adverb"},
    "Canasta":{def:"A card game for two to six players, popular in the mid-twentieth century.",pos:"noun"},
    "proportions":{def:"The relative sizes of different parts of something.",pos:"noun"}
  },
  quiz:[
    {question:"What did the family find in the kitchen drawer?",options:["Torches","Board games","Candles","An emergency radio"],correct:2,
     feedback:"'My parents found the candles. We have a tin of them in the kitchen drawer for exactly this purpose.'"},
    {question:"When was the power supposed to come back, according to the electricity company?",options:["By eight","By nine","By ten","By midnight"],correct:2,
     feedback:"The company said 'the fault... would be repaired by ten.'"},
    {question:"Who taught the family the card game?",options:["The mother","The father","The narrator","The grandmother"],correct:3,
     feedback:"'My grandmother, who was visiting, said she would teach us to play a card game called Spite and Malice.'"},
    {question:"What happened when the power came back at ten?",options:["Everyone felt relieved and went to bed","Every screen lit up simultaneously and the kitchen felt different","They kept playing cards","They blew out the candles one by one"],correct:1,
     feedback:"'Every screen in the house lit up simultaneously, along with the refrigerator hum and the ceiling lights.'"}
  ]
});

