      "verdict": { def: "a formal decision made in a legal case", pos: "noun" },
      "revision": { def: "the act of changing or correcting something previously stated", pos: "noun" },
      "logistical": { def: "relating to practical organisation and planning", pos: "adjective" },
      "contradict": { def: "to say or show that something is not true", pos: "verb" }
