JOURNEY_STORIES['australia'].push({
  id:"j-australia-4", journeyId:"australia", order:4,
  title:"The Shape of the Throw", emoji:"🪃", genre:"Culture / Learning",
  wordCount:304, readMins:3,
  blurb:"An elder teaches a group of students about the boomerang — and explains why returning is not the point.",
  paragraphs:[
    "The elder's name was Derek, and he had been teaching at schools and community events for over twenty years. He held the boomerang flat across both palms when he introduced it, so that everyone could see the shape — the two arms meeting at a slight angle, one face slightly curved and one flat. He said most people thought boomerangs were for hunting. He said they were right, but that most people also thought the point was that they came back. He said the return was a misunderstanding.",
    "Hunting boomerangs, he explained, were heavy and did not return. They were thrown at animals and were designed to travel far and hit hard. The returning boomerang was a different tool — lighter, used to flush birds out of long grass toward nets, or used in practice and play. The idea that all boomerangs return was a simplification that had become the whole story.",
    "He demonstrated the throw. It required the boomerang to be held nearly vertical, not horizontal the way most people assumed, and thrown with a spin from the wrist. The boomerang curved up and around and came back to within two metres of where he stood. A student tried and sent it straight into the ground six metres ahead. Derek did not laugh. He repositioned the student's arm angle and said try again.",
    "He talked about the different designs used across the continent — each region had its own shapes and purposes, accumulated over tens of thousands of years. He said when people reduced all of that to 'it comes back', something important was lost.",
    "On the bus home, a student asked the teacher whether they could buy one. The teacher said probably. The student said they wanted the kind that actually comes back. The teacher looked out the window."
  ],
  vocabulary:{
    "elder":{def:"A respected older person in a community, often with traditional knowledge.",pos:"noun"},
    "boomerang":{def:"A curved throwing tool developed by Aboriginal Australians.",pos:"noun"},
    "flush":{def:"Here: to drive animals or birds out of hiding into the open.",pos:"verb"},
    "simplification":{def:"Reducing something complex to a shorter or easier version, often losing detail.",pos:"noun"},
    "vertical":{def:"Pointing straight up and down, at a right angle to the ground.",pos:"adjective"},
    "horizontal":{def:"Parallel to the ground; flat and level.",pos:"adjective"},
    "accumulated":{def:"Gathered or built up over a long period of time.",pos:"verb"}
  },
  quiz:[
    {question:"What common misunderstanding about boomerangs does Derek correct?",options:["That they are made from wood","That they were invented in Australia","That the point of a boomerang is that it returns","That they were used only in ceremonies"],correct:2,
     feedback:"Derek explains that hunting boomerangs did not return — the returning boomerang was a different tool used for different purposes."},
    {question:"What was the returning boomerang actually used for?",options:["Hunting large animals","Throwing competitions between communities","Flushing birds toward nets, and for practice and play","Marking the borders of territory"],correct:2,
     feedback:"'The returning boomerang was a different tool — lighter, used to flush birds out of long grass toward nets, or used in practice and play.'"},
    {question:"How should the boomerang be held for throwing?",options:["Flat and horizontal, like a frisbee","Nearly vertical, with a spin from the wrist","At a 45-degree angle, like a cricket ball","Held by one end and released without spin"],correct:1,
     feedback:"'It required the boomerang to be held nearly vertical, not horizontal the way most people assumed, and thrown with a spin from the wrist.'"},
    {question:"What did Derek say was lost when the boomerang was reduced to 'it comes back'?",options:["The names of the people who made them","Something important — the full diversity of designs and purposes from across the continent","The technique for throwing them correctly","The original materials used to make them"],correct:1,
     feedback:"'He said when people reduced all of that to \"it comes back\", something important was lost' — tens of thousands of years of regional knowledge and design."}
  ]
});

