    "pão de queijo":{def:"Small Brazilian cheese bread rolls, light and chewy, often eaten as a snack.",pos:"noun"},
    "skewers":{def:"Long thin metal or wooden rods used to hold food while it is cooked over a fire.",pos:"noun"}
